#include 
using namespace std;
int main() {
string a, b, c;
int na, nb, r;
cin &gt;&gt; a;
na = a.size();
cin &gt;&gt; b;
nb = b.size();
cin &gt;&gt; c;
r = 0;
for (int i = 0; i &lt; nb; i++) {
for (int j = 1; j &lt; min(na+1, nb-i+1); j++) {
bool f = true;
int d = 0;
for (int k = 0; k &lt; j; k++) {
if (a[k] != b[i+k]) {
if (c[k] == '1')  { d += 1; }
else { f = false; }
}
}
if (f &amp;&amp; d &lt;= 2) { r = (r + j*j) % 1000000007; }
}
}
cout &lt;&lt; r &lt;&lt; endl;
return 0;
}






